subsections.example:
module intro_example;
  logic clk;
  initial begin
    clk = 0;
    forever #5 clk = ~clk;
  end
endmodule

module lit_syntax;
  logic [3:0] a = 4'b1010;
  logic [7:0] b = 8'hFF;
endmodule

module int_logic_lits;
  logic [3:0] v1 = 4'b10xz;
  int         v2 = 32'd10;
endmodule

module real_lits;
  real a = 1.25;
  real b = 3.0e-2;
endmodule

`timescale 1ns/1ps
module time_lits;
  initial begin
    #10ns;
  end
endmodule

module string_lits;
  string s = "Hello, SystemVerilog";
endmodule

module array_lits;
  int a[3] = '{1, 2, 3};
  int b[3] = '{default: 0};
endmodule

typedef struct {
  int    id;
  string name;
} item_t;

module struct_lits;
  item_t it = '{id: 1, name: "pkt"};
endmodule

typedef logic [7:0] byte_t;
module dt_syntax;
  byte_t b;
  int    arr[4];
endmodule

module dt_integer;
  byte      b;
  shortint  s;
  int       i;
  longint   l;
endmodule

module dt_real;
  real      r;
  shortreal sr;
endmodule

function void log_msg(string s);
  $display("%s", s);
endfunction

module dt_string;
  string s = "abc";
  initial s = {s, "def"};
endmodule

module dt_event;
  event ev;
  initial begin
    #10 -> ev;
  end
  initial begin
    @ev;
    $display("Event at %0t", $time);
  end
endmodule

typedef logic [31:0] addr_t;
module dt_udt;
  addr_t addr;
endmodule

typedef struct packed {
  logic [7:0] a;
  logic [7:0] b;
} pair_t;

class Packet;
  rand bit [3:0] cmd;
  function new();
    cmd = 0;
  endfunction
endclass

logic [7:0] v;
int         i;
initial begin
  i = 42;
  v = logic'(i);
end

Base b;
Derived d;
if (!$cast(d, b)) $display("cast failed");

bit [31:0] flat;
struct packed {bit [7:0] a,b,c,d;} s;
initial begin
  flat = 32'hA5A5_FF00;
  s = flat;
end

logic [7:0] v;
initial begin
  v[3:0]   = 4'hF;
  v[0 +:4] = 4'hA;
end

int q[$];
initial begin
  q.push_back(1);
  $display("size=%0d", q.size());
end

int da[];
initial begin
  da = new[16];
  da = new[32](da);
end

task sum_array(input int a[], output int s);
  s = 0;
  foreach (a[i]) s += a[i];
endtask

int hits[string];
string k;
initial begin
  hits["p0"] = 1;
  if (hits.first(k)) $display("first=%s", k);
end

int a[string], b[string];
initial begin
  a["x"] = 1;
  b = a;
end

task clear_assoc(ref int a[string]);
  foreach (a[k]) a.delete(k);
endtask

int q[$];
initial begin
  q.push_back(1);
  q.push_front(0);
  q.pop_back();
end

module proc_intro;
  initial $display("Start");
  final   $display("End");
endmodule

unique case (sel)
  2'b00: y = a;
  2'b01: y = b;
  default: y = '0;
endcase

int i;
initial begin
  for (i = 0; i < 10; i++) $display(i);
  do i++; while (i < 20);
end

for (int i=0; i<10; i++) begin
  if (i == 5) break;
end

begin : blk
  int x;
end

always_ff @(posedge clk, negedge rst_n)
  if (!rst_n) q <= 0;
  else        q <= d;

initial fork
  #5  $display("A");
  #10 $display("B");
join

function int add(int a, b);
  return a + b;
endfunction

task delay_print(time t);
  #t $display("after delay");
endtask
